def _get_db() -> sqlite3.Connection:
    if "db" not in g:
        conn = sqlite3.connect(DATABASE_URL, uri=True, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        g.db = conn
    return g.db

def _init_db() -> None:
    db = _get_db()
    db.execute(
        """
        CREATE TABLE IF NOT EXISTS items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            created_at REAL NOT NULL
        )
        """
    )
    db.commit()

@app.before_request
def _before_request() -> None:
    _init_db()

@app.teardown_appcontext
def _teardown_db(exception: Optional[BaseException]) -> None:
    db = g.pop("db", None)
    if db is not None:
        db.close()

@app.after_request
def _after_request(resp: Response) -> Response:
    resp.headers["X-Request-ID"] = request.headers.get("X-Request-ID", "")
    return resp

@app.get("/health")
def health() -> Dict[str, Any]:
    return {"status": "ok", "service": APP_NAME, "environment": ENVIRONMENT}

@app.get("/work")
def do_work() -> Dict[str, Any]:
    delay_ms = int(request.args.get("delay_ms", "50"))
    count = int(request.args.get("count", "3"))
    name = request.args.get("name", "demo")

    apm.label(delay_ms=delay_ms, count=count, endpoint="/work")

    t0 = time.time()
    db = _get_db()

    for i in range(count):
        db.execute(
            "INSERT INTO items(name, created_at) VALUES(?, ?)",
            (f"{name}-{i}", time.time()),
        )
    db.commit()

    rows = db.execute(
        "SELECT id, name, created_at FROM items ORDER BY id DESC LIMIT ?",
        (min(50, count * 5),),
    ).fetchall()

    time.sleep(max(0, delay_ms) / 1000.0)
    t1 = time.time()

    return {
        "ok": True,
        "duration_ms": int((t1 - t0) * 1000),
        "inserted": count,
        "sample": [dict(r) for r in rows],
    }

@app.post("/echo")
def echo() -> Response:
    apm.label(endpoint="/echo")
    payload = request.get_json(silent=True)
    if payload is None:
        payload = request.get_data(as_text=True)
    return jsonify(
        {
            "method": request.method,
            "path": request.path,
            "headers": {k: v for k, v in request.headers.items()},
            "query": request.args.to_dict(flat=True),
            "body": payload,
        }
    )

