def error() -> Dict[str, Any]:
    apm.label(endpoint="/error")
    logger.info("About to raise an error for APM capture")
    raise RuntimeError("Intentional error for APM stacktrace capture")

@app.get("/sql")
def sql_demo() -> Dict[str, Any]:
    apm.label(endpoint="/sql")
    db = _get_db()
    _init_db()
    db.execute("INSERT INTO items(name, created_at) VALUES(?, ?)", ("sql-demo", time.time()))
    db.commit()
    rows = db.execute("SELECT COUNT(*) AS cnt FROM items").fetchone()
    return {"count": int(rows["cnt"])}

